import{_ as e,o as t,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"10. Anti Discrimination","description":"","frontmatter":{"title":"10. Anti Discrimination","eba":"Biomedical Engineers 2025-2028","topics":["flexible-work","preliminary","discrimination"]},"headers":[],"relativePath":"ebas/biomedical-engineers/preliminary/10-anti-discrimination.md","filePath":"ebas/biomedical-engineers/preliminary/10-anti-discrimination.md"}'),a={name:"ebas/biomedical-engineers/preliminary/10-anti-discrimination.md"};function o(s,i,c,l,m,d){return t(),n("div",null,[...i[0]||(i[0]=[r('<h1 id="_10-anti-discrimination" tabindex="-1">10. Anti Discrimination <a class="header-anchor" href="#_10-anti-discrimination" aria-label="Permalink to &quot;10. Anti Discrimination&quot;">​</a></h1><p><strong>10.1</strong> Those covered by this Agreement respect and value the diversity of the work force and protection against unfair treatment and unlawful discrimination on the basis of race, colour, sex, sexual orientation, breastfeeding, gender identity, intersex status, age, physical or mental disability, marital status, family or carer’s responsibilities, subjection to family and domestic violence, pregnancy, religion, political opinion, national extraction or social origin.</p><p><strong>10.2</strong> Accordingly, in fulfilling their obligations under the Dispute Resolution Procedure, those covered by the Agreement must make every reasonable endeavour to ensure that neither</p><p>the Agreement provisions nor their operation are directly or indirectly unlawfully discriminatory in their effects.</p><p><strong>10.3</strong> Nothing in this clause is taken to affect:</p><p><strong>(a)</strong> any different treatment (or treatment having different effects) which is specifically exempted under Commonwealth or State anti-discrimination legislation;</p><p><strong>(b)</strong> an Employee, Employer or registered organisation, pursuing matters of discrimination in any State or Federal jurisdiction, including any application to the Australian Human Rights Commission; or</p><p><strong>(c)</strong> the exemptions in section 351(2) of the Act.</p>',8)])])}const f=e(a,[["render",o]]);export{g as __pageData,f as default};
